var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"좌현! 10시 방향! 적 기동부대, 제 5차 공세 개시! 고속접근!","JPN":"左舷！　10時方向！\\n敵の機動部隊、第5次攻勢を開始！　高速接近中！","ENG":"Port side! 10 o' clock! Enemy unit commencing 5th attack wave! Incoming rapidly!","TWN":"左舷！10點鐘方向！敵人的機動部隊展開第五次攻勢！高速接近中！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"정면! 적 본영으로부터 네임드 제 3종 침식체 전진 중! 식별명...... <color=#ffd34c>오거</color>!","JPN":"正面！　敵の本営よりネームド第3種の侵食体が前進中！\\n識別名……<color=#ffd34c>オーガ</color>！","ENG":"Towards the bow! Category 3 C.O advancing from enemy formation! Code name... <color=#ffd34c>Ogre</color>!","TWN":"正面！敵人大本營中出現第三種侵蝕體！識別為……<color=#ffd34c>食人魔</color>！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"리플레이서 나이트, 궤도 추적 실패! 위치 확인 불가! 주의 요망!","JPN":"リプレイサー・ナイト、軌道追跡に失敗！\\n位置確認できません！　ご注意を！","ENG":"Failed to track the Replacer Knight's trajectory! Bogey position unknown! Extreme caution advised!","TWN":"克隆·騎士，軌道追蹤失敗！無法確定位置！請各位嚴加提防！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"알트 소대! 현 위치를 유지할 경우 20초 후에 포위됩니다! 즉시 이동하세요!","JPN":"アルト小隊！\\n現在の位置を維持した場合、20秒後に取り囲まれます！　すぐに移動してください！","ENG":"ALT Squad! You’ll be surrounded in 20 seconds if you maintain your current position! Get out of there, now!","TWN":"阿爾特小隊！待在目前位置20秒後會被包圍！馬上移動！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"똑똑, 안녕하세요, 여러분. 많이 바쁘시죠?","JPN":"トントン！　こんにちは。皆さん、お忙しいですよね？","ENG":"Knock, knock! Hi everyone. Got your hands full, huh?","TWN":"咚咚，你們好啊，各位。你們現在很忙嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어......? 여, 여긴 어떻게 들어온 거에요?","JPN":"えっ……？　ど、どうやってここに入ったんですか？","ENG":"Huh? H-how did you get in here?","TWN":"呃……？妳、妳是怎麼進到這裡來的？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"함교는 외부인 출입 금지라고요!","JPN":"艦橋は部外者立ち入り禁止です！","ENG":"The bridge is for authorized personnel only!","TWN":"艦橋是禁止外人出入的！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 조금 신경 쓰이는 게 있어서요.","JPN":"ははは、少し気になることがあって。","ENG":"Haha, there was just something bothering me, you see.","TWN":"哈哈，我只是有件好奇的事情。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"잠깐만 확인하고 돌아갈게요.","JPN":"ちょっとだけ確認して帰ります。","ENG":"I’ll be just a minute. Just need to check something.","TWN":"我確認一下就走。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아, 아니! 뭘 맘대로 앉는 거에요?!","JPN":"い、いや！　何を勝手に座ってるんですか？","ENG":"W-what?! Who said you can have a seat there?!","TWN":"啊，不行！妳怎麼自己就坐下了？！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"이봐요, 내 말 듣고 있어요? ......그거 건드리면 안 된다고!","JPN":"ちょっと、私の話聞いてますか？　それ触っちゃダメですって！","ENG":"Hey, are you even listening to me? You shouldn’t touch that!","TWN":"喂，妳有在聽我說話嗎？……不能碰那個！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"......레나 양? 지금 어디에 한눈 팔고 있죠?","JPN":"……レナ？　何よそ見してるんですか？","ENG":"Lena? What’s keeping you distracted?","TWN":"……蕾娜小姐，妳在分什麼心？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"지금 같은 상황에 저 혼자 전투지원을 맡는 건 무리라고요!","JPN":"こんな状況で私一人で戦闘支援をするなんて、無理ですよ！","ENG":"You know I can't provide combat support all by myself in a situation like this!","TWN":"現在這種情況，我沒辦法一個人擔任戰鬥支援！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아......? 그, 그건 그런데......","JPN":"え……？　そ、それはそうだけど……","ENG":"Oh... I-I know, but...","TWN":"啊……？沒、沒錯，可是……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"바쁘신 것 같은데 일 보세요. 전 안 도와주셔도 돼요.","JPN":"お忙しいようなので、仕事に戻ってください。私はお手伝い不要ですよ。","ENG":"Looks like your friend could use a hand. Please go ahead. Don’t mind me. I don’t need your help.","TWN":"你們好像很忙的樣子，我是不會幫忙的喔。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"누가 돕는대?!","JPN":"誰が手伝うって言った！？","ENG":"I wasn’t trying to help you!","TWN":"誰要妳幫忙了？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"......레나 양!","JPN":"……レナ！","ENG":"Lena!","TWN":"……蕾娜小姐！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};